import React from "react";
import { PlusIcon } from "./icons";

interface Props {
 id: number;
 name: string;
 weight: string;
 price: number;
 oldPrice?: number;
 discount?: string;
 image: string;
 onAdd: () => void;
}

const ProductCard: React.FC<Props> = ({ name, weight, price, oldPrice, discount, image, onAdd }) => (
 <div className="gallery-card group flex flex-col h-full animate-reveal">
  {/* Product Showcase */}
  <div className="relative aspect-square mb-6 overflow-hidden bg-bg-parchment flex items-center justify-center">
   {discount && (
    <div className="absolute top-4 left-4 z-10">
     <span className="bg-accent-gold text-white text-[10px] font-black px-2 py-1 uppercase tracking-widest">{discount}</span>
    </div>
   )}

   <img
    src={image}
    alt={name}
    className="w-[85%] h-[85%] object-contain mix-blend-multiply group-hover:scale-110 transition-transform duration-700 ease-out"
   />

   {/* Quick Add Overlay (Desktop) */}
   <div className="absolute inset-x-0 bottom-0 p-4 translate-y-full group-hover:translate-y-0 transition-transform duration-500 hidden md:block">
    <button
     onClick={(e) => { e.stopPropagation(); onAdd(); }}
     className="btn-boutique w-full"
    >
     Add to bag
    </button>
   </div>
  </div>

  {/* Product Details */}
  <div className="flex flex-col flex-1">
   <div className="flex justify-between items-start gap-4 mb-2">
    <h3 className="text-[15px] leading-snug font-heading font-bold text-fg-main uppercase tracking-wide">{name}</h3>
   </div>

   <p className="text-[12px] font-medium text-fg-muted uppercase tracking-widest mb-4">{weight}</p>

   <div className="mt-auto flex items-center justify-between">
    <div className="flex items-baseline gap-2">
     <span className="text-[18px] font-heading font-black text-fg-main">{price} ₽</span>
     {oldPrice && <span className="text-[14px] text-fg-muted line-through font-medium">{oldPrice} P</span>}
    </div>

    {/* Mobile-only Circle Add */}
    <button
     onClick={(e) => { e.stopPropagation(); onAdd(); }}
     className="md:hidden w-10 h-10 rounded-full border border-border-rich flex items-center justify-center text-accent-gold active:bg-accent-gold active:text-white transition-all"
    >
     <PlusIcon size={18} />
    </button>
   </div>
  </div>
 </div>
);

export default ProductCard;
