"use client";
import React from "react";
import { SearchIcon, UserIcon } from "./icons";

const Header = () => {
 return (
  <header className="artisanal-header">
   {/* Brand Identity */}
   <div className="flex flex-col">
    <span className="brand-title text-accent-gold">Пекарня</span>
    <span className="font-heading font-black text-[22px] tracking-tight mt-[-4px]">СМЫСЛ ЕСТЬ</span>
   </div>

   {/* Navigation */}
   <nav className="hidden md:flex ml-16 gap-8">
    {["Breads", "Pastries", "Healthy", "Collections"].map((item) => (
     <a key={item} href="#" className="text-[13px] font-bold text-fg-soft hover:text-accent-gold transition-colors uppercase tracking-widest">
      {item}
     </a>
    ))}
   </nav>

   {/* Search & Actions */}
   <div className="ml-auto flex items-center gap-6">
    <div className="flex items-center gap-2 text-fg-muted hover:text-fg-main cursor-pointer transition-colors">
     <SearchIcon size={18} />
     <span className="text-[13px] font-bold hidden lg:inline uppercase tracking-widest">Search</span>
    </div>

    <div className="w-[1px] h-6 bg-border-light" />

    <button className="flex items-center gap-3 group">
     <div className="w-9 h-9 rounded-full bg-bg-parchment flex items-center justify-center text-accent-gold group-hover:bg-accent-gold group-hover:text-white transition-all shadow-sm">
      <UserIcon size={18} />
     </div>
     <span className="text-[13px] font-bold uppercase tracking-widest text-fg-soft group-hover:text-fg-main transition-colors">Profile</span>
    </button>
   </div>
  </header>
 );
};

export default Header;
